import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I’m really glad you reached out today. How are you feeling right now?"
    }
  ]);

  const [input, setInput] = useState("");

  // Therapist memory
  const [memory, setMemory] = useState({
    cause: null,
    duration: null,
    severity: null,
    thoughtPattern: null
  });

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ---------------- GREETING ONLY ---------------- */
    if (greetings.includes(text)) {
      return "Hello. Take your time. What’s been on your mind lately?";
    }

    /* ---------------- STRESS IDENTIFICATION ---------------- */
    if (text.includes("stress") || text.includes("stressed") || text.includes("pressure")) {
      return "Thank you for sharing that. Stress can come from many places. What do you feel is causing it for you right now?";
    }

    /* ---------------- CAUSES ---------------- */
    if (text.includes("exam") || text.includes("study") || text.includes("college")) {
      setMemory({ ...memory, cause: "studies" });
      return "Academic pressure can be intense. How long have you been feeling stressed about your studies?";
    }

    if (text.includes("job") || text.includes("work")) {
      setMemory({ ...memory, cause: "work" });
      return "Work stress can slowly build up. Since when has this been affecting you?";
    }

    if (text.includes("family")) {
      setMemory({ ...memory, cause: "family" });
      return "Family pressure can be emotionally heavy. How long has this been troubling you?";
    }

    if (text.includes("relationship") || text.includes("breakup")) {
      setMemory({ ...memory, cause: "relationship" });
      return "Relationship stress can hurt deeply. How long have you been feeling this way?";
    }

    if (text.includes("money") || text.includes("financial")) {
      setMemory({ ...memory, cause: "financial" });
      return "Financial worries can feel overwhelming. How long has this stress been present?";
    }

    if (text.includes("future") || text.includes("career")) {
      setMemory({ ...memory, cause: "future" });
      return "Uncertainty about the future can be scary. Since when have these thoughts been stressing you?";
    }

    /* ---------------- DURATION ---------------- */
    if (
      text.includes("days") ||
      text.includes("weeks") ||
      text.includes("months") ||
      text.includes("long time")
    ) {
      setMemory({ ...memory, duration: text });
      return "That’s a long time to carry stress. On a scale of 1 to 10, how intense does it feel right now?";
    }

    /* ---------------- SEVERITY ---------------- */
    if (text.match(/\b([7-9]|10)\b/)) {
      setMemory({ ...memory, severity: "high" });
      return "That sounds really overwhelming. How has this stress been affecting your sleep, focus, or mood?";
    }

    if (text.match(/\b([1-6])\b/)) {
      setMemory({ ...memory, severity: "moderate" });
      return "Thank you for being honest. How does this stress usually show up — mentally or physically?";
    }

    /* ---------------- IMPACT ---------------- */
    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("focus") ||
      text.includes("anxiety") ||
      text.includes("headache")
    ) {
      return "When stress affects your body and routine, it’s a sign you’ve been carrying a lot. Would you like to try a short calming exercise, or do you want to talk more first?";
    }

    /* ================= CBT STYLE QUESTIONS ================= */

    if (
      text.includes("i can't") ||
      text.includes("i will fail") ||
      text.includes("not good enough") ||
      text.includes("always") ||
      text.includes("never")
    ) {
      setMemory({ ...memory, thoughtPattern: "negative" });
      return "I notice you’re being quite hard on yourself. Let’s pause for a moment. What evidence do you have that this thought is completely true?";
    }

    if (memory.thoughtPattern === "negative") {
      return "That’s understandable. Now, if a close friend were in your situation, what would you say to them instead?";
    }

    /* ================= BREATHING EXERCISE ================= */

    if (text.includes("breathing") || text.includes("exercise")) {
      return `Let’s try a simple breathing exercise together 🌿

• Inhale slowly through your nose for 4 seconds  
• Hold gently for 2 seconds  
• Exhale through your mouth for 6 seconds  

Repeat this 5 times.  
Tell me when you’re done, or how it felt.`;
    }

    /* ================= GROUNDING ================= */

    if (text.includes("grounding") || text.includes("panic")) {
      return `Let’s do a quick grounding exercise (5-4-3-2-1):

• Name 5 things you can see  
• 4 things you can feel  
• 3 things you can hear  
• 2 things you can smell  
• 1 thing you can taste  

Take your time. This helps bring your mind back to the present.`;
    }

    /* ---------------- SUGGEST SOLUTION ---------------- */
    if (text.includes("help") || text.includes("solution")) {
      return `Based on what you’ve shared, here are some gentle steps that might help:

• Break tasks into small, manageable parts  
• Reduce self-pressure — progress matters more than perfection  
• Schedule short daily breaks  
• Express feelings instead of holding them in  
• Practice calming techniques regularly  

Which one feels doable right now?`;
    }

    /* ---------------- HIGH STRESS CARE ---------------- */
    if (memory.severity === "high") {
      return "I want you to know this — feeling this way doesn’t mean you’re weak. It means you’ve been trying very hard for a long time. I’m here with you. What feels hardest right now?";
    }

    /* ---------------- FALLBACK ---------------- */
    return "I’m listening. You don’t have to explain perfectly — just share what feels important right now.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = { sender: "bot", text: therapistReply(input) };

    setMessages((prev) => [...prev, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe, judgment-free space</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you’re feeling..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
